import java.util.PriorityQueue;

List<Integer> topK(int[] stream, int k) {
    PriorityQueue<Integer> heap = new PriorityQueue<>();
    for (int value : stream) {
        heap.offer(value);
        if (heap.size() > k) {
            heap.poll();
        }
    }
    return new ArrayList<>(heap);
}

def has_cycle(adj):
    visited = set()
    stack = set()

    def dfs(node):
        if node in stack:
            return True
        if node in visited:
            return False
        visited.add(node)
        stack.add(node)
        for neighbor in adj[node]:
            if dfs(neighbor):
                return True
        stack.remove(node)
        return False

    for node in adj:
        if dfs(node):
            return True
    return False

